#include "mix_kernels_cpu.h"

#define ELEMENTS_PER_THREAD (8)
#define FUSION_DEGREE (4)

struct half2 {
  uint16_t x;
  uint16_t y;
};

static inline uint16_t float_to_half_bits(float f) {
  union {
    float f;
    uint32_t u;
  } v;
  v.f = f;

  uint32_t sign = (v.u >> 31) & 0x1;
  uint32_t exp = (v.u >> 23) & 0xFF;
  uint32_t mant = v.u & 0x7FFFFF;

  uint16_t hsign = static_cast<uint16_t>(sign << 15);

  if (exp == 255) {
    if (mant != 0) return static_cast<uint16_t>(hsign | 0x7E00);
    return static_cast<uint16_t>(hsign | 0x7C00);
  }

  int32_t new_exp = static_cast<int32_t>(exp) - 127 + 15;
  if (new_exp >= 31) {
    return static_cast<uint16_t>(hsign | 0x7C00);
  }
  if (new_exp <= 0) {
    if (new_exp < -10) return hsign;
    mant |= 0x800000;
    uint32_t shift = static_cast<uint32_t>(14 - new_exp);
    uint16_t hmant = static_cast<uint16_t>(mant >> shift);
    if ((mant >> (shift - 1)) & 1) hmant++;
    return static_cast<uint16_t>(hsign | hmant);
  }

  uint16_t hexp = static_cast<uint16_t>(new_exp << 10);
  uint16_t hmant = static_cast<uint16_t>(mant >> 13);
  if (mant & 0x00001000) hmant++;
  return static_cast<uint16_t>(hsign | hexp | (hmant & 0x03FF));
}

static inline float half_bits_to_float(uint16_t h) {
  uint32_t sign = (h >> 15) & 0x1;
  uint32_t exp = (h >> 10) & 0x1F;
  uint32_t mant = h & 0x03FF;

  uint32_t fsign = sign << 31;
  uint32_t fexp;
  uint32_t fmant;

  if (exp == 0) {
    if (mant == 0) {
      fexp = 0;
      fmant = 0;
    } else {
      int e = -1;
      uint32_t m = mant;
      do {
        e++;
        m <<= 1;
      } while ((m & 0x0400) == 0);
      m &= 0x03FF;
      fexp = static_cast<uint32_t>(127 - 15 - e) << 23;
      fmant = m << 13;
    }
  } else if (exp == 31) {
    fexp = 0xFFu << 23;
    fmant = mant << 13;
  } else {
    fexp = static_cast<uint32_t>(exp - 15 + 127) << 23;
    fmant = mant << 13;
  }

  union {
    uint32_t u;
    float f;
  } out;
  out.u = fsign | fexp | fmant;
  return out.f;
}

template <class T>
inline T conv_int(const int i) {
  return static_cast<T>(i);
}

template <>
inline half2 conv_int<half2>(const int i) {
  uint16_t h = float_to_half_bits(static_cast<float>(i));
  return half2{h, h};
}

template <class T>
inline T mad(const T a, const T b, const T c) {
  return a * b + c;
