template <>
inline half2 mad<half2>(const half2 a, const half2 b, const half2 c) {
  float ax = half_bits_to_float(a.x);
  float ay = half_bits_to_float(a.y);
  float bx = half_bits_to_float(b.x);
  float by = half_bits_to_float(b.y);
  float cx = half_bits_to_float(c.x);
  float cy = half_bits_to_float(c.y);
  return half2{float_to_half_bits(ax * bx + cx), float_to_half_bits(ay * by + cy)};
}

