#define ELEMENTS_PER_THREAD (8)
#define FUSION_DEGREE (4)

struct half2 {
  float x;
  float y;
};

template <class T>
inline T conv_int(const int i) {
  return static_cast<T>(i);
}

template <>
inline half2 conv_int<half2>(const int i) {
  const float v = static_cast<float>(i);
  return half2{v, v};
}

template <class T>
inline T mad(const T a, const T b, const T c) {
  return a * b + c;
}

template <>
inline half2 mad<half2>(const half2 a, const half2 b, const half2 c) {
  return half2{a.x * b.x + c.x, a.y * b.y + c.y};
}

template <class T>
inline bool equal(const T a, const T b) {
  return a == b;
}

template <>
inline bool equal<half2>(const half2 a, const half2 b) {
  return (a.x == b.x) && (a.y == b.y);
}

static inline bool IsFP16Supported(void) { return false; }

template <class T, int blockdim, unsigned int granularity,
          unsigned int fusion_degree, unsigned int compute_iterations,
          bool TemperateUnroll>
static void benchmark_func_cpu(T seed, T* g_data, int gridDimX) {
  (void)TemperateUnroll;
  const unsigned int blockSize = blockdim;
  const long long total_threads = static_cast<long long>(gridDimX) * blockSize;
  const long long big_stride =
      static_cast<long long>(gridDimX) * blockSize * granularity;

#pragma omp parallel for schedule(static)
  for (long long tid = 0; tid < total_threads; ++tid) {
    const long long blockIdx = tid / blockSize;
    const long long threadIdx = tid % blockSize;
    const long long idx = blockIdx * blockSize * granularity + threadIdx;
    const long long stride = blockSize;

    T tmps[granularity];
    for (unsigned int k = 0; k < fusion_degree; k++) {
      for (unsigned int j = 0; j < granularity; j++) {
        tmps[j] = g_data[idx + static_cast<long long>(j) * stride +
                         static_cast<long long>(k) * big_stride];

        for (unsigned int i = 0; i < compute_iterations; i++) {
          tmps[j] = mad(tmps[j], tmps[j], seed);
        }
      }

      T sum = conv_int<T>(0);
      for (unsigned int j = 0; j < granularity; j += 2) {
        sum = mad(tmps[j], tmps[j + 1], sum);
      }

      if (equal(sum, conv_int<T>(-1))) {
        g_data[idx + static_cast<long long>(k) * big_stride] = sum;
      }
    }
  }
}

template <typename F>
static float timed_ms(F&& f) {
  const auto t0 = std::chrono::high_resolution_clock::now();
  f();
  const auto t1 = std::chrono::high_resolution_clock::now();
  return std::chrono::duration<float, std::milli>(t1 - t0).count();
}

static void runbench_warmup(double* cd, long size) {
  const long reduced_grid_size = size / (ELEMENTS_PER_THREAD) / 128;
  const int BLOCK_SIZE = 256;
  const int TOTAL_REDUCED_BLOCKS = static_cast<int>(reduced_grid_size / BLOCK_SIZE);

  benchmark_func_cpu<short, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE, 0, true>(
      static_cast<short>(1), reinterpret_cast<short*>(cd), TOTAL_REDUCED_BLOCKS);
}

