#define MIN(a, b) ((a) <= (b) ? (a) : (b))

static void calculate_temp(int iteration, float *power, float *temp_src, float *temp_dst, int grid_cols, int grid_rows,
                           int border_cols, int border_rows, float Cap, float Rx, float Ry, float Rz, float step,
                           float time_elapsed, int blockCols, int blockRows) {
    (void)time_elapsed;

    const float amb_temp_local = 80.0f;
    const float step_div_Cap = step / Cap;
    const float Rx_1 = 1.0f / Rx;
    const float Ry_1 = 1.0f / Ry;
    const float Rz_1 = 1.0f / Rz;

    const int small_block_rows = BLOCK_SIZE - iteration * 2;
    const int small_block_cols = BLOCK_SIZE - iteration * 2;

#pragma omp parallel for collapse(2) schedule(static)
    for (int by = 0; by < blockRows; by++) {
        for (int bx = 0; bx < blockCols; bx++) {
            float temp_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
            float power_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
            float temp_t[BLOCK_SIZE][BLOCK_SIZE];
            bool computed[BLOCK_SIZE][BLOCK_SIZE];

            int blkY = small_block_rows * by - border_rows;
            int blkX = small_block_cols * bx - border_cols;
            int blkYmax = blkY + BLOCK_SIZE - 1;
            int blkXmax = blkX + BLOCK_SIZE - 1;

            for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    int yidx = blkY + ty;
                    int xidx = blkX + tx;
                    int index = grid_cols * yidx + xidx;
                    if (IN_RANGE(yidx, 0, grid_rows - 1) && IN_RANGE(xidx, 0, grid_cols - 1)) {
                        temp_on_cuda[ty][tx] = temp_src[index];
                        power_on_cuda[ty][tx] = power[index];
                    } else {
                        temp_on_cuda[ty][tx] = 0.0f;
                        power_on_cuda[ty][tx] = 0.0f;
                    }
                    computed[ty][tx] = false;
                }
            }

            int validYmin = (blkY < 0) ? -blkY : 0;
            int validYmax = (blkYmax > grid_rows - 1) ? BLOCK_SIZE - 1 - (blkYmax - grid_rows + 1) : BLOCK_SIZE - 1;
            int validXmin = (blkX < 0) ? -blkX : 0;
            int validXmax = (blkXmax > grid_cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - grid_cols + 1) : BLOCK_SIZE - 1;

            for (int i = 0; i < iteration; i++) {
                for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                        computed[ty][tx] = false;
                        if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) && IN_RANGE(ty, i + 1, BLOCK_SIZE - i - 2) &&
                            IN_RANGE(tx, validXmin, validXmax) && IN_RANGE(ty, validYmin, validYmax)) {
                            computed[ty][tx] = true;

                            int N = ty - 1;
                            int S = ty + 1;
                            int W = tx - 1;
                            int E = tx + 1;

                            N = (N < validYmin) ? validYmin : N;
                            S = (S > validYmax) ? validYmax : S;
                            W = (W < validXmin) ? validXmin : W;
                            E = (E > validXmax) ? validXmax : E;

                            temp_t[ty][tx] = temp_on_cuda[ty][tx] +
                                             step_div_Cap *
                                                 (power_on_cuda[ty][tx] +
                                                  (temp_on_cuda[S][tx] + temp_on_cuda[N][tx] - 2.0f * temp_on_cuda[ty][tx]) *
                                                      Ry_1 +
                                                  (temp_on_cuda[ty][E] + temp_on_cuda[ty][W] - 2.0f * temp_on_cuda[ty][tx]) *
                                                      Rx_1 +
                                                  (amb_temp_local - temp_on_cuda[ty][tx]) * Rz_1);
                        }
                    }
                }

                if (i == iteration - 1) break;

                for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                        if (computed[ty][tx]) temp_on_cuda[ty][tx] = temp_t[ty][tx];
                    }
                }
            }

            for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    if (computed[ty][tx]) {
                        int yidx = blkY + ty;
                        int xidx = blkX + tx;
                        int index = grid_cols * yidx + xidx;
                        temp_dst[index] = temp_t[ty][tx];
                    }
                }
            }
        }
    }
}

int compute_tran_temp(float *MatrixPower, float *MatrixTemp[2], int col, int row, int total_iterations, int num_iterations,
                      int blockCols, int blockRows, int borderCols, int borderRows) {
    float grid_height = chip_height / row;
    float grid_width = chip_width / col;

    float Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
    float Rx = grid_width / (2.0f * K_SI * t_chip * grid_height);
    float Ry = grid_height / (2.0f * K_SI * t_chip * grid_width);
    float Rz = t_chip / (K_SI * grid_height * grid_width);

    float max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    float step = PRECISION / max_slope;
    float t;
    float time_elapsed;
    time_elapsed = 0.001f;

    int src = 1, dst = 0;

    for (t = 0; t < total_iterations; t += num_iterations) {
        int temp = src;
        src = dst;
        dst = temp;
        calculate_temp(MIN(num_iterations, total_iterations - (int)t), MatrixPower, MatrixTemp[src], MatrixTemp[dst], col,
                       row, borderCols, borderRows, Cap, Rx, Ry, Rz, step, time_elapsed, blockCols, blockRows);
    }
    return dst;
}

