static void calculate_temp(int iteration, float *power, float *temp_src, float *temp_dst, int grid_cols, int grid_rows,
                           int border_cols, int border_rows, float Cap, float Rx, float Ry, float Rz, float step,
                           float time_elapsed) {
    (void)border_cols;
    (void)border_rows;
    (void)time_elapsed;

    float amb_temp_local = 80.0f;
    float step_div_Cap = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;

    int size = grid_rows * grid_cols;
    float *temp_aux = NULL;
    if (iteration > 1) {
        temp_aux = (float *)malloc(sizeof(float) * size);
        if (!temp_aux) {
            fatal((char *)"unable to allocate memory");
            return;
        }
    }

    const float *in = temp_src;
    float *out = (iteration % 2 == 1) ? temp_dst : temp_aux;

    for (int it = 0; it < iteration; it++) {
#pragma omp parallel for collapse(2)
        for (int y = 0; y < grid_rows; y++) {
            for (int x = 0; x < grid_cols; x++) {
                int idx = y * grid_cols + x;
                int N = (y == 0) ? 0 : (y - 1);
                int S = (y == grid_rows - 1) ? (grid_rows - 1) : (y + 1);
                int W = (x == 0) ? 0 : (x - 1);
                int E = (x == grid_cols - 1) ? (grid_cols - 1) : (x + 1);

                float temp_c = in[idx];
                float temp_n = in[N * grid_cols + x];
                float temp_s = in[S * grid_cols + x];
                float temp_w = in[y * grid_cols + W];
                float temp_e = in[y * grid_cols + E];

                out[idx] = temp_c + step_div_Cap *
                                        (power[idx] + (temp_s + temp_n - 2.0f * temp_c) * Ry_1 +
                                         (temp_e + temp_w - 2.0f * temp_c) * Rx_1 +
                                         (amb_temp_local - temp_c) * Rz_1);
            }
        }

        if (it != iteration - 1) {
            in = out;
            if (out == temp_dst)
                out = temp_aux;
            else
                out = temp_dst;
        }
    }

    if (temp_aux)
        free(temp_aux);
}

