#pragma omp parallel for collapse(2)
    for (int j = 0; j < ny; ++j) {
        for (int i = 0; i < nx; ++i) {
            int c = i + j * nx;

            int W = (i == 0) ? c : c - 1;
            int E = (i == nx - 1) ? c : c + 1;
            int N = (j == 0) ? c : c - nx;
            int S = (j == ny - 1) ? c : c + nx;

            float temp1, temp2, temp3;
            temp1 = temp2 = tIn[c];
            temp3 = tIn[c + xy];
            tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                    + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb;

            c += xy;
            W += xy;
            E += xy;
            N += xy;
            S += xy;

            for (int k = 1; k < nz - 1; ++k) {
                temp1 = temp2;
                temp2 = temp3;
                temp3 = tIn[c + xy];
                tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                        + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb;
                c += xy;
                W += xy;
                E += xy;
                N += xy;
                S += xy;
            }

            temp1 = temp2;
            temp2 = temp3;
            tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                    + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb;
        }
    }
}

void hotspot_opt1(float *p, float *tIn, float *tOut,
                  int nx, int ny, int nz,
                  float Cap,
                  float Rx, float Ry, float Rz,
                  float dt, int numiter)
{
    float ce, cw, cn, cs, ct, cb, cc;
    float stepDivCap = dt / Cap;
    ce = cw = stepDivCap / Rx;
    cn = cs = stepDivCap / Ry;
    ct = cb = stepDivCap / Rz;
    cc = 1.0f - (2.0f * ce + 2.0f * cn + 3.0f * ct);

    size_t s = (size_t)nx * ny * nz;
    size_t bytes = sizeof(float) * s;
    float *tIn_d = (float *)malloc(bytes);
    float *tOut_d = (float *)malloc(bytes);
    float *p_d = (float *)malloc(bytes);

    memcpy(tIn_d, tIn, bytes);
    memcpy(p_d, p, bytes);

    long long start = get_time();
    for (int i = 0; i < numiter; ++i) {
        hotspotOpt1_omp(p_d, tIn_d, tOut_d, stepDivCap, nx, ny, nz, ce, cw, cn, cs, ct, cb, cc);
        float *t = tIn_d;
        tIn_d = tOut_d;
        tOut_d = t;
    }
    long long stop = get_time();
    float time = (float)((stop - start) / (1000.0 * 1000.0));
    printf("Time: %.3f (s)\n", time);

    memcpy(tOut, tOut_d, bytes);

    free(p_d);
    free(tIn_d);
    free(tOut_d);
}

