                                  + cn * tIn_d[N] + cb * temp1 + ct * temp3 + stepDivCap * p_d[c] + ct * 80.0f;
                        c += xy;
                        W += xy;
                        E += xy;
                        N += xy;
                        S += xy;

                        for (int k = 1; k < nz - 1; ++k) {
                            temp1 = temp2;
                            temp2 = temp3;
                            temp3 = tIn_d[c + xy];
                            tOut_d[c] = cc * temp2 + cw * tIn_d[W] + ce * tIn_d[E] + cs * tIn_d[S]
                                      + cn * tIn_d[N] + cb * temp1 + ct * temp3 + stepDivCap * p_d[c] + ct * 80.0f;
                            c += xy;
                            W += xy;
                            E += xy;
                            N += xy;
                            S += xy;
                        }
                        temp1 = temp2;
                        temp2 = temp3;
                        tOut_d[c] = cc * temp2 + cw * tIn_d[W] + ce * tIn_d[E] + cs * tIn_d[S]
                                  + cn * tIn_d[N] + cb * temp1 + ct * temp3 + stepDivCap * p_d[c] + ct * 80.0f;
                    }
                }
            }
        }

        float *t = tIn_d;
        tIn_d = tOut_d;
        tOut_d = t;
    }
    long long stop = get_time();
    float time = (float)((stop - start) / (1000.0 * 1000.0));
    printf("Time: %.3f (s)\n", time);

    memcpy(tOut, tOut_d, s);

    free(p_d);
    free(tIn_d);
    free(tOut_d);
}

