static void hotspotOpt1(float *p, float *tIn, float *tOut, float sdc,
                        int nx, int ny, int nz,
                        float ce, float cw,
                        float cn, float cs,
                        float ct, float cb,
                        float cc) {
    float amb_temp_local = 80.0f;
    int xy = nx * ny;

    int i_max = (nx / 64) * 64;
    int j_max = (ny / 4) * 4;

    #pragma omp parallel for collapse(2)
    for (int j = 0; j < j_max; ++j) {
        for (int i = 0; i < i_max; ++i) {
            int c = i + j * nx;

            int W = (0 == i) ? c : c - 1;
            int E = (nx - 1 == i) ? c : c + 1;
            int N = (0 == j) ? c : c - nx;
            int S = (ny - 1 == j) ? c : c + nx;

            float temp1, temp2, temp3;
            temp1 = temp2 = tIn[c];
            temp3 = tIn[c + xy];
            tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                    + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp_local;
            c = c + xy;
            W = W + xy;
            E = E + xy;
            N = N + xy;
            S = S + xy;

            for (int k = 1; nz - 1 > k; ++k) {
                temp1 = temp2;
                temp2 = temp3;
                temp3 = tIn[c + xy];
                tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                        + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp_local;
                c = c + xy;
                W = W + xy;
                E = E + xy;
                N = N + xy;
                S = S + xy;
            }
            temp1 = temp2;
            temp2 = temp3;
            tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                    + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp_local;
        }
    }
}

