int loadData(char *filename, Record **records_out, LatLong **locations_out) {
  FILE *flist, *fp;
  int i = 0;
  char dbname[64];
  int recNum = 0;

  int capacity = 1024;
  Record *records = (Record *)malloc(sizeof(Record) * (size_t)capacity);
  LatLong *locations = (LatLong *)malloc(sizeof(LatLong) * (size_t)capacity);
  if (!records || !locations) {
    fprintf(stderr, "memory allocation failed\n");
    free(records);
    free(locations);
    exit(1);
  }

  flist = fopen(filename, "r");
  if (!flist) {
    fprintf(stderr, "error opening filelist\n");
    free(records);
    free(locations);
    exit(1);
  }

  while (!feof(flist)) {
    if (fscanf(flist, "%63s\n", dbname) != 1) {
      if (feof(flist)) break;
      fprintf(stderr, "error reading filelist\n");
      free(records);
      free(locations);
      fclose(flist);
      exit(0);
    }

    fp = fopen(dbname, "r");
    if (!fp) {
      printf("error opening a db\n");
      free(records);
      free(locations);
      fclose(flist);
      exit(1);
    }

    while (!feof(fp)) {
      Record record;
      LatLong latLong;
      char *ret = fgets(record.recString, 49, fp);
      if (!ret) break;
      fgetc(fp);
      if (feof(fp)) break;

      char substr[6];
      for (i = 0; i < 5; i++) substr[i] = *(record.recString + i + 28);
      substr[5] = '\0';
      latLong.lat = (float)atof(substr);

      for (i = 0; i < 5; i++) substr[i] = *(record.recString + i + 33);
      substr[5] = '\0';
      latLong.lng = (float)atof(substr);

      if (recNum >= capacity) {
        capacity *= 2;
        Record *newRecords = (Record *)realloc(records, sizeof(Record) * (size_t)capacity);
        LatLong *newLocations =
            (LatLong *)realloc(locations, sizeof(LatLong) * (size_t)capacity);
        if (!newRecords || !newLocations) {
          fprintf(stderr, "memory allocation failed\n");
          free(newRecords ? newRecords : records);
          free(newLocations ? newLocations : locations);
          fclose(fp);
          fclose(flist);
          exit(1);
        }
        records = newRecords;
        locations = newLocations;
      }

      locations[recNum] = latLong;
      records[recNum] = record;
      recNum++;
    }
    fclose(fp);
  }
  fclose(flist);

  *records_out = records;
  *locations_out = locations;
  return recNum;
}

void findLowest(Record *records, float *distances, int numRecords, int topN) {
  int i, j;
  float val;
  int minLoc;
  Record tempRec;
  float tempDist;

  for (i = 0; i < topN; i++) {
    minLoc = i;
    for (j = i; j < numRecords; j++) {
      val = distances[j];
      if (val < distances[minLoc]) minLoc = j;
    }

    tempRec = records[i];
    records[i] = records[minLoc];
    records[minLoc] = tempRec;

    tempDist = distances[i];
    distances[i] = distances[minLoc];
    distances[minLoc] = tempDist;

    records[i].distance = distances[i];
  }
}

