static void euclid(const LatLong *locations, float *distances, int numRecords, float lat, float lng) {
  int globalId;
#pragma omp parallel for schedule(static)
  for (globalId = 0; globalId < numRecords; globalId++) {
    const LatLong *latLong = locations + globalId;
    float dlat = lat - latLong->lat;
    float dlng = lng - latLong->lng;
    distances[globalId] = sqrtf(dlat * dlat + dlng * dlng);
  }
}

