            for (i = 0; 5 > i; i++) substr[i] = *(record.recString + i + 33);
            substr[5] = '\0';
            latLong.lng = (float)atof(substr);

            if ((size_t)recNum >= cap) {
                size_t newCap = (cap == 0) ? 1024 : (cap * 2);
                Record *newRecords = (Record *)realloc(*records, newCap * sizeof(Record));
                LatLong *newLocations = (LatLong *)realloc(*locations, newCap * sizeof(LatLong));
                if (!newRecords || !newLocations) {
                    free(newRecords);
