          maximum(temp[t_index_y - 1][t_index_x - 1] + ref[t_index_y - 1][t_index_x - 1],
                  temp[t_index_y][t_index_x - 1] - penalty,
                  temp[t_index_y - 1][t_index_x] - penalty);
    }
  }

  for (tx = 0; tx < BLOCK_SIZE; tx++) {
    int index = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + (cols + 1);
    for (ty = 0; ty < BLOCK_SIZE; ty++) {
      matrix_cuda[index + ty * cols] = temp[ty + 1][tx + 1];
    }
  }
}

static inline void needle_cuda_shared_1(int *referrence, int *matrix_cuda, int cols, int penalty, int i, int block_width) {
#pragma omp parallel for schedule(static)
  for (int bx = 0; bx < i; bx++) {
    needle_block_1(referrence, matrix_cuda, cols, penalty, i, block_width, bx);
  }
}

