static inline int maximum(int a, int b, int c) {
  int k;
  if (a <= b)
    k = b;
  else
    k = a;

  if (k <= c)
    return c;
  else
    return k;
}

static inline void needle_block_compute(int* referrence, int* matrix_cuda, int cols, int penalty,
                                        int b_index_x, int b_index_y) {
  int index_base = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;
  int index = index_base + (cols + 1);
  int index_n = index_base + 1;
  int index_w = index_base + cols;
  int index_nw = index_base;

  int temp[BLOCK_SIZE + 1][BLOCK_SIZE + 1];
  int ref[BLOCK_SIZE][BLOCK_SIZE];

  temp[0][0] = matrix_cuda[index_nw];

  for (int ty = 0; ty < BLOCK_SIZE; ty++) {
    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
      ref[ty][tx] = referrence[index + cols * ty + tx];
    }
  }

  for (int tx = 0; tx < BLOCK_SIZE; tx++) {
    temp[tx + 1][0] = matrix_cuda[index_w + cols * tx];
    temp[0][tx + 1] = matrix_cuda[index_n + tx];
  }

  for (int y = 1; y <= BLOCK_SIZE; y++) {
    for (int x = 1; x <= BLOCK_SIZE; x++) {
      temp[y][x] = maximum(temp[y - 1][x - 1] + ref[y - 1][x - 1],
                           temp[y][x - 1] - penalty,
                           temp[y - 1][x] - penalty);
    }
  }

  for (int ty = 0; ty < BLOCK_SIZE; ty++) {
    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
      matrix_cuda[index + ty * cols + tx] = temp[ty + 1][tx + 1];
    }
  }
}

