static inline int maximum(int a, int b, int c) {
  int k;
  if (b >= a) k = b;
  else k = a;
  if (c >= k) return c;
  else return k;
}

static inline void needle_cuda_shared_1_block(
    int *referrence, int *matrix_cuda, int cols, int penalty, int i, int block_width, int bx) {
  (void)block_width;
  int b_index_x = bx;
  int b_index_y = i - 1 - bx;

  int base = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;
  int index_nw = base;
  int index_w = base + cols;

  int temp[BLOCK_SIZE + 1][BLOCK_SIZE + 1];
  int ref[BLOCK_SIZE][BLOCK_SIZE];

  temp[0][0] = matrix_cuda[index_nw];

  for (int tx = 0; tx < BLOCK_SIZE; tx++) {
    int index = base + tx + (cols + 1);
    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
      ref[ty][tx] = referrence[index + cols * ty];
    }
  }

  for (int tx = 0; tx < BLOCK_SIZE; tx++) {
    temp[tx + 1][0] = matrix_cuda[index_w + cols * tx];
  }

  for (int tx = 0; tx < BLOCK_SIZE; tx++) {
    int index_n = base + tx + 1;
    temp[0][tx + 1] = matrix_cuda[index_n];
  }

  for (int m = 0; m < BLOCK_SIZE; m++) {
    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
      if (m >= tx) {
        int t_index_x = tx + 1;
        int t_index_y = m - tx + 1;
        temp[t_index_y][t_index_x] = maximum(
            temp[t_index_y - 1][t_index_x - 1] + ref[t_index_y - 1][t_index_x - 1],
            temp[t_index_y][t_index_x - 1] - penalty,
            temp[t_index_y - 1][t_index_x] - penalty);
      }
    }
  }

  for (int m = BLOCK_SIZE - 2; 0 <= m; m--) {
    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
      if (m >= tx) {
        int t_index_x = tx + BLOCK_SIZE - m;
        int t_index_y = BLOCK_SIZE - tx;
        temp[t_index_y][t_index_x] = maximum(
            temp[t_index_y - 1][t_index_x - 1] + ref[t_index_y - 1][t_index_x - 1],
            temp[t_index_y][t_index_x - 1] - penalty,
            temp[t_index_y - 1][t_index_x] - penalty);
      }
    }
  }

  for (int tx = 0; tx < BLOCK_SIZE; tx++) {
