static void dynproc_kernel(int iteration, int* gpuWall, int* gpuSrc, int* gpuResults,
                           int cols, int rows, int startStep, int border) {
    (void)rows;
    (void)border;

    if (iteration <= 0) return;

    int* bufA = new int[cols];
    int* bufB = new int[cols];

    int* curr = gpuSrc;
