            int up = curr[x];
            int right = curr[(x == cols - 1) ? (cols - 1) : (x + 1)];
            int shortest = MIN(left, up);
            shortest = MIN(shortest, right);
            next[x] = shortest + gpuWall[rowOffset + x];
        }

        curr = next;
        next = (next == bufA) ? bufB : bufA;
    }

    memcpy(gpuResults, curr, sizeof(int) * cols);

    delete[] bufA;
    delete[] bufB;
}

