                    shortest = MIN(shortest, right);
                    int index = cols * (startStep + i) + xidx;
                    result_sh[tx] = shortest + gpuWall[index];
                }
            }

            if (iteration - 1 == i) break;

            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                if (computed[tx]) prev[tx] = result_sh[tx];
            }
        }

        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            int xidx = blkX + tx;
            if (computed[tx] && IN_RANGE(xidx, 0, cols - 1)) {
                gpuResults[xidx] = result_sh[tx];
            }
        }
    }
}

