        for (int j = 0; j < cols; j++) {
            printf("%.5f ", J[i * cols + j]);
        }
        printf("\n");
    }
#endif

    printf("Computation Done\n");

    free(I);
    free(J);
    free(C_cuda);
    free(E_C);
    free(W_C);
    free(N_C);
    free(S_C);
    free(c);
}

