  if (nproc > 0) omp_set_num_threads(nproc);

  srand48(SEED);

  PStream* stream = nullptr;
  if (n > 0) stream = new SimStream(n);
  else stream = new FileStream(infilename);

  double t1 = gettime();

#ifdef ENABLE_PARSEC_HOOKS
