// Translated CUDA state
float *work_mem_h = NULL;
float *coord_h = NULL;
float *work_mem_d = NULL;
float *coord_d = NULL;
int   *center_table_d = NULL;
bool  *switch_membership_d = NULL;
Point *p_dev = NULL;
static int iter = 0;

static inline float d_dist(int p1, int p2, int num, int dim, float *coord_arr) {
  float retval = 0.0f;
  for (int i = 0; i < dim; i++) {
    float tmp = coord_arr[(i * num) + p1] - coord_arr[(i * num) + p2];
    retval += tmp * tmp;
  }
  return retval;
}

void allocDevMem(int num, int dim) {
  center_table_d = (int*)malloc(num * sizeof(int));
  switch_membership_d = (bool*)malloc(num * sizeof(bool));
  p_dev = (Point*)malloc(num * sizeof(Point));
  coord_d = (float*)malloc((size_t)num * dim * sizeof(float));
  if (!center_table_d || !switch_membership_d || !p_dev || !coord_d) {
    fprintf(stderr, "allocation failed in allocDevMem\n");
    exit(EXIT_FAILURE);
  }
}

void allocHostMem(int num, int dim) {
  coord_h = (float*)malloc((size_t)num * dim * sizeof(float));
  if (!coord_h) {
    fprintf(stderr, "allocation failed in allocHostMem\n");
    exit(EXIT_FAILURE);
  }
}

void freeDevMem() {
  free(center_table_d); center_table_d = NULL;
  free(switch_membership_d); switch_membership_d = NULL;
  free(p_dev); p_dev = NULL;
  free(coord_d); coord_d = NULL;
}

void freeHostMem() {
  free(coord_h); coord_h = NULL;
}

float pgain(long x, Points *points, float z, long int *numcenters, int kmax, bool *is_center_arr,
            int *center_table_arr, bool *switch_membership_arr, bool isCoordChangedFlag,
            double *serial_t_acc, double *cpu_to_gpu_t_acc, double *gpu_to_cpu_t_acc,
            double *alloc_t_acc, double *kernel_t_acc, double *free_t_acc) {
  double t1, t2;

  int stride = (int)(*numcenters + 1);
  int K = (int)(*numcenters);
  int num = (int)points->num;
  int dim = points->dim;
  int nThread = num;

  t1 = gettime();

  work_mem_h = (float*)malloc((size_t)stride * (nThread + 1) * sizeof(float));
  if (!work_mem_h) {
    fprintf(stderr, "allocation failed for work_mem_h\n");
    exit(EXIT_FAILURE);
  }

  if (iter == 0) {
    allocHostMem(num, dim);
  }

  int count = 0;
  for (int i = 0; i < num; i++) {
    if (is_center_arr[i]) {
      center_table_arr[i] = count++;
    }
  }

  if (isCoordChangedFlag || iter == 0) {
    for (int i = 0; i < dim; i++) {
      for (int j = 0; j < num; j++) {
        coord_h[(num * i) + j] = points->p[j].coord[i];
      }
    }
  }

  t2 = gettime();
  *serial_t_acc += (t2 - t1) * 1000.0;

  t1 = gettime();

  work_mem_d = (float*)malloc((size_t)stride * (nThread + 1) * sizeof(float));
  if (!work_mem_d) {
    fprintf(stderr, "allocation failed for work_mem_d\n");
    exit(EXIT_FAILURE);
  }

  if (iter == 0) {
    allocDevMem(num, dim);
  }

  t2 = gettime();
  *alloc_t_acc += (t2 - t1) * 1000.0;

  t1 = gettime();

  if (isCoordChangedFlag || iter == 0) {
    memcpy(coord_d, coord_h, (size_t)num * dim * sizeof(float));
  }
  memcpy(center_table_d, center_table_arr, (size_t)num * sizeof(int));
  memcpy(p_dev, points->p, (size_t)num * sizeof(Point));

  memset((void*)switch_membership_d, 0, (size_t)num * sizeof(bool));
  memset((void*)work_mem_d, 0, (size_t)stride * (nThread + 1) * sizeof(float));

  t2 = gettime();
  *cpu_to_gpu_t_acc += (t2 - t1) * 1000.0;

  t1 = gettime();

  #pragma omp parallel for schedule(static)
  for (int tid = 0; tid < num; tid++) {
    float *lower = &work_mem_d[(size_t)tid * stride];
    float x_cost = d_dist(tid, (int)x, num, dim, coord_d) * p_dev[tid].weight;

    if (p_dev[tid].cost > x_cost) {
      switch_membership_d[tid] = 1;
      lower[K] += x_cost - p_dev[tid].cost;
    } else {
      lower[center_table_d[p_dev[tid].assign]] += p_dev[tid].cost - x_cost;
    }
  }

  t2 = gettime();
  *kernel_t_acc += (t2 - t1) * 1000.0;

  t1 = gettime();

  memcpy(work_mem_h, work_mem_d, (size_t)stride * (nThread + 1) * sizeof(float));
  memcpy(switch_membership_arr, switch_membership_d, (size_t)num * sizeof(bool));

  t2 = gettime();
  *gpu_to_cpu_t_acc += (t2 - t1) * 1000.0;

  int number_of_centers_to_close = 0;
  float gl_cost_of_opening_x = z;
  float *gl_lower = &work_mem_h[(size_t)stride * nThread];

  for (int i = 0; i < num; i++) {
    if (is_center_arr[i]) {
      float low = z;
      for (int j = 0; j < num; j++) {
        low = low + work_mem_h[(size_t)j * stride + center_table_arr[i]];
      }

      gl_lower[center_table_arr[i]] = low;

      if (0 < low) {
        ++number_of_centers_to_close;
        work_mem_h[(size_t)i * stride + K] -= low;
      }
    }
    gl_cost_of_opening_x = gl_cost_of_opening_x + work_mem_h[(size_t)i * stride + K];
  }

  if (0 > gl_cost_of_opening_x) {
    for (int i = 0; i < num; i++) {
      bool close_center = 0 < gl_lower[center_table_arr[points->p[i].assign]];
      if (switch_membership_arr[i] || close_center) {
        points->p[i].cost = dist(points->p[i], points->p[x], dim) * points->p[i].weight;
        points->p[i].assign = x;
      }
    }

    for (int i = 0; i < num; i++) {
      if (is_center_arr[i] && 0 < gl_lower[center_table_arr[i]]) {
        is_center_arr[i] = false;
      }
    }

    if (0 <= x && num > x) {
      is_center_arr[x] = true;
    }
    *numcenters = *numcenters + 1 - number_of_centers_to_close;
  } else {
    gl_cost_of_opening_x = 0;
  }

  t1 = gettime();
  free(work_mem_h);
  work_mem_h = NULL;
  t2 = gettime();
  *serial_t_acc += (t2 - t1) * 1000.0;

  t1 = gettime();
  free(work_mem_d);
  work_mem_d = NULL;
  t2 = gettime();
  *free_t_acc += (t2 - t1) * 1000.0;

  iter++;
  return -gl_cost_of_opening_x;
}

