typedef struct {
	int mat;
	double E;
} SamplePair;

static int cmp_pair_mat(const void *a, const void *b)
{
	const SamplePair *pa = (const SamplePair *)a;
	const SamplePair *pb = (const SamplePair *)b;
	return (pa->mat > pb->mat) - (pa->mat < pb->mat);
}

static int cmp_pair_energy(const void *a, const void *b)
{
	const SamplePair *pa = (const SamplePair *)a;
	const SamplePair *pb = (const SamplePair *)b;
	if (pa->E < pb->E) return -1;
	if (pa->E > pb->E) return 1;
	return 0;
}

